module RefModule(  
    input wire clk,  
    input wire update,  
    input wire [3:0] timeout,  
    output reg reset  
);  
    reg [3:0] unused_counter;  

    always @(posedge clk) begin  
        if (update)  
            unused_counter <= timeout;  
        else if (unused_counter > 0)  
            unused_counter <= unused_counter - 1;  

        reset <= (unused_counter == 0);  
    end  
endmodule
